'use strict';
/**
 * REGRESSION — FRG-204
 * Walk animations stutter/freeze mid-movement due to timer accumulation issues.
 *
 * Root cause: walk frame timer was not using a while-loop, so large deltaMs values
 * (e.g. when tab was backgrounded or frame rate dropped) only advanced walkFrame
 * once per update() call, leaving walkTimer > walkFrameMs and causing the animation
 * to stutter or freeze.
 *
 * Fix: advance walkFrame in a while-loop, consuming all accumulated intervals so
 * walkTimer is always < walkFrameMs after each update().
 *
 * Tests run against the local dev server (http://localhost:5174) which serves
 * the feature/frg-204-fix-walk-animation branch.
 *
 * The page does NOT expose window._gameEngine by default, so we intercept
 * index.html via page.route() and inject the exposure before the script executes.
 *
 * Test layout:
 *   1. moveTo resets walk state — walkFrame=0 and walkTimer=0 on new movement
 *   2. Large deltaMs — update(1000) advances all 5 frames, walkTimer holds only remainder
 *   3. moveTo resets dirty walk state — pre-set walkFrame/walkTimer are cleared on moveTo
 *   4. Live sim regression — no character gets stuck on same walkFrame while walking for 30s
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:5174';

// walkFrameMs is 200ms per frame (4-frame cycle)
const WALK_FRAME_MS = 200;
const WALK_FRAME_COUNT = 4;

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Intercept index.html served at / and inject window._gameEngine = engine
 * so tests can call page.evaluate(() => window._gameEngine.*).
 */
async function injectEngineExposure(page) {
  await page.route('**/', async (route) => {
    const response = await route.fetch();
    let body = await response.text();
    body = body.replace(
      '// ── Initial state ──',
      '// ── Initial state (QA injection) ──\nwindow._gameEngine = engine;'
    );
    await route.fulfill({ response, body });
  });
}

/**
 * Click start overlay (if present) and set timeScale.
 */
async function startEngine(page, timeScale = 1) {
  const overlay = page.locator('#start-overlay');
  if (await overlay.isVisible()) {
    await overlay.click();
  }
  if (timeScale !== 1) {
    await page.evaluate((scale) => {
      if (window._gameEngine) window._gameEngine.timeScale = scale;
    }, timeScale);
  }
}

/**
 * Read walk state from all characters.
 */
async function getWalkStates(page) {
  return page.evaluate(() =>
    window._gameEngine.characters.map(c => ({
      id: c.id,
      action: c.action,
      walkFrame: c.walkFrame,
      walkTimer: c.walkTimer,
      walkFrameMs: c.walkFrameMs,
      tx: c.tx,
      ty: c.ty,
    }))
  );
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-204: Walk Animation', () => {

  // ── TEST 1: moveTo resets walk state ──────────────────────────────────────

  test('moveTo resets walkFrame to 0 and walkTimer to 0', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const nyx = engine.characters.find(c => c.id === 'nyx');

      // Start from nyx's initial position in the apartment sector
      nyx.tx = 3; nyx.ty = 4;
      nyx.prevTx = 3; nyx.prevTy = 4;
      nyx.action = 'idle';
      nyx.path = [];
      nyx.moveProgress = 0;

      // Call moveTo and verify it resets walk state
      const ok = nyx.moveTo(7, 4);

      return {
        moveToSucceeded: ok,
        walkFrame: nyx.walkFrame,
        walkTimer: nyx.walkTimer,
        action: nyx.action,
        pathLength: nyx.path.length,
      };
    });

    console.log('moveTo result:', JSON.stringify(result));

    expect(result.moveToSucceeded, 'moveTo should find a valid path').toBe(true);
    expect(result.action, 'action should be walking after moveTo').toBe('walking');
    expect(result.walkFrame, 'walkFrame should be 0 when movement starts').toBe(0);
    expect(result.walkTimer, 'walkTimer should be 0 when movement starts').toBe(0);
    expect(result.pathLength, 'path should not be empty after moveTo').toBeGreaterThan(0);
  });

  // ── TEST 2: Large deltaMs advances all frames without stutter ─────────────

  test('update(1000ms) consumes all accumulated walk frames — walkTimer < walkFrameMs', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const nyx = engine.characters.find(c => c.id === 'nyx');

      // Place nyx at a known walkable position in the apartment and start walking
      // with a long path (7 tiles) so movement doesn't complete within 1000ms
      // (moveSpeed=2 tiles/s → 500ms/tile → 7 tiles = 3500ms to complete)
      nyx.tx = 3;  nyx.ty = 4;
      nyx.prevTx = 3; nyx.prevTy = 4;
      nyx.path = [
        { tx: 4, ty: 4 }, { tx: 5, ty: 4 }, { tx: 6, ty: 4 },
        { tx: 7, ty: 4 }, { tx: 8, ty: 4 }, { tx: 9, ty: 4 }, { tx: 10, ty: 4 },
      ];
      nyx.action = 'walking';
      nyx.walkFrame = 0;
      nyx.walkTimer = 0;
      nyx.moveProgress = 0;

      const before = { walkFrame: nyx.walkFrame, walkTimer: nyx.walkTimer };

      // Simulate 1000ms — at walkFrameMs=200 this is exactly 5 frame intervals
      nyx.update(1000);

      const after = { walkFrame: nyx.walkFrame, walkTimer: nyx.walkTimer, action: nyx.action };

      // Expected frame advances: floor(1000/200) = 5
      // Starting at frame 0: 0→1→2→3→0→1 → final walkFrame = (0+5)%4 = 1
      // Remainder: 1000 - 5*200 = 0ms
      const expectedFrameAdvances = Math.floor(1000 / 200);  // 5
      const expectedWalkFrame = (0 + expectedFrameAdvances) % 4;  // 1
      const expectedWalkTimerRemainder = 1000 % 200;  // 0

      return { before, after, expectedWalkFrame, expectedWalkTimerRemainder };
    });

    console.log('Before update(1000):', JSON.stringify(result.before));
    console.log('After  update(1000):', JSON.stringify(result.after));
    console.log('Expected walkFrame:', result.expectedWalkFrame, '| Expected walkTimer remainder:', result.expectedWalkTimerRemainder);

    // The critical assertion: walkTimer must be less than walkFrameMs (200ms)
    // — if the bug were present, walkTimer would be 800ms (only 1 frame consumed)
    expect(result.after.walkTimer,
      `walkTimer should be < ${200}ms after consuming all intervals — got ${result.after.walkTimer}ms`
    ).toBeLessThan(200);

    // Verify the exact frame position (all 5 advances consumed)
    expect(result.after.walkFrame,
      `walkFrame should be ${result.expectedWalkFrame} after 5 frame advances (0→1→2→3→0→1)`
    ).toBe(result.expectedWalkFrame);

    // Character should still be walking (path not exhausted)
    expect(result.after.action, 'character should still be walking after 1000ms on a long path').toBe('walking');
  });

  // ── TEST 3: moveTo resets dirty walk state ────────────────────────────────

  test('moveTo clears non-zero walkFrame and walkTimer from previous movement', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const nyx = engine.characters.find(c => c.id === 'nyx');

      // Simulate mid-walk dirty state (as it would be during ongoing movement)
      nyx.tx = 3; nyx.ty = 4;
      nyx.prevTx = 3; nyx.prevTy = 4;
      nyx.action = 'walking';
      nyx.walkFrame = 3;   // non-zero
      nyx.walkTimer = 150; // non-zero
      nyx.path = [{ tx: 4, ty: 4 }];
      nyx.moveProgress = 0.5;

      const before = { walkFrame: nyx.walkFrame, walkTimer: nyx.walkTimer };

      // Issue a new moveTo — this should reset walk state regardless of prior state
      const ok = nyx.moveTo(8, 4);

      const after = { walkFrame: nyx.walkFrame, walkTimer: nyx.walkTimer, action: nyx.action };

      return { moveToSucceeded: ok, before, after };
    });

    console.log('Before moveTo (dirty state):', JSON.stringify(result.before));
    console.log('After  moveTo:', JSON.stringify(result.after));

    expect(result.moveToSucceeded, 'moveTo should find a valid path').toBe(true);
    expect(result.after.walkFrame,
      `walkFrame should reset to 0 — was ${result.before.walkFrame}`
    ).toBe(0);
    expect(result.after.walkTimer,
      `walkTimer should reset to 0 — was ${result.before.walkTimer}ms`
    ).toBe(0);
  });

  // ── TEST 4: Live sim — walkFrame cycles and walkTimer stays < walkFrameMs ──

  test('walkFrame cycles through all 4 frames and walkTimer never accumulates above walkFrameMs', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    // Drive the sim via engine._updateCharacters() — the same method the live RAF loop calls.
    // This avoids headless RAF throttling issues while still exercising the real engine path.
    // We advance 5 seconds of sim time in 200ms steps (25 steps) — the same granularity as
    // the walk frame interval — and observe walkFrame and walkTimer throughout.
    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const nyx = engine.characters.find(c => c.id === 'nyx');

      // Place nyx at a known walkable apartment position with a 20-tile path.
      // At moveSpeed=2, this takes 10 sim-seconds — far longer than our 5s observation window.
      nyx.tx = 3;  nyx.ty = 4;
      nyx.prevTx = 3; nyx.prevTy = 4;
      nyx.path = Array.from({ length: 20 }, (_, i) => ({ tx: 4 + i, ty: 4 }));
      nyx.action = 'walking';
      nyx.walkFrame = 0;
      nyx.walkTimer = 0;
      nyx.moveProgress = 0;

      const STEP_MS = 200;   // advance 200ms per step (= 1 walk frame interval)
      const STEPS = 25;      // 25 * 200ms = 5 sim-seconds of walking

      const seenFrames = new Set();
      const timerViolations = []; // walkTimer >= walkFrameMs at any point after update()
      const observations = [];

      for (let i = 0; i < STEPS; i++) {
        nyx.update(STEP_MS);
        seenFrames.add(nyx.walkFrame);
        observations.push({ walkFrame: nyx.walkFrame, walkTimer: nyx.walkTimer });

        if (nyx.walkTimer >= nyx.walkFrameMs) {
          timerViolations.push({ step: i, walkTimer: nyx.walkTimer, walkFrameMs: nyx.walkFrameMs });
        }

        // Stop early if nyx is no longer walking (shouldn't happen with 20-tile path)
        if (nyx.action !== 'walking') break;
      }

      return {
        seenFrames: [...seenFrames],
        timerViolations,
        observations: observations.slice(0, 8), // first 8 for logging
        finalAction: nyx.action,
        finalWalkTimer: nyx.walkTimer,
        finalWalkFrame: nyx.walkFrame,
      };
    });

    console.log('Unique walkFrames seen:', result.seenFrames.sort().join(', '));
    console.log('Timer violations (walkTimer >= 200ms after update):', result.timerViolations.length);
    console.log('First 8 observations:', result.observations.map(o =>
      `f${o.walkFrame}/t${o.walkTimer}ms`
    ).join(' → '));
    console.log('Final state: action=%s walkFrame=%d walkTimer=%dms',
      result.finalAction, result.finalWalkFrame, result.finalWalkTimer);

    // Character should still be walking (20-tile path, only 5s simulated)
    expect(result.finalAction, 'character should still be walking after 5 sim-seconds on 20-tile path').toBe('walking');

    // All 4 walk frames must appear: 25 steps / 4 frames = 6.25 full cycles
    expect(result.seenFrames.length,
      `walkFrame must cycle through all 4 values (0–3), only saw: ${result.seenFrames.sort().join(', ')}`
    ).toBe(4);

    // walkTimer must never exceed walkFrameMs after an update() — this is the fix assertion
    // (without the while-loop fix, walkTimer could be up to 1000ms after a large-delta update)
    expect(result.timerViolations.length,
      `walkTimer exceeded walkFrameMs (${WALK_FRAME_MS}ms) on ${result.timerViolations.length} step(s): ` +
      JSON.stringify(result.timerViolations)
    ).toBe(0);
  });
});

