      // Ensure random wander mode (not AI-LLM mode) so decisions happen deterministically
      engine.aiMode = false;

      const TICKS = 24; // 24 × 5000ms = 120 sim-seconds

      // Record initial spawn positions
      const initialPos = {};
      for (const c of engine.characters) {
        initialPos[c.id] = { tx: Math.round(c.tx), ty: Math.round(c.ty) };
      }

      const everActive = {};   // charId → true if ever walked or interacted
      const errors = [];

      for (const c of engine.characters) {
        everActive[c.id] = false;
      }

      for (let tick = 0; tick < TICKS; tick++) {
