          engine.manualTick(1);
        } catch (e) {
          errors.push({ tick, simMs: tick * 5000, msg: String(e) });
          break;
        }

        for (const c of engine.characters) {
          const tx = Math.round(c.tx);
          const ty = Math.round(c.ty);
          // Active = moved from spawn OR entered a non-idle action
