    if (stability.stuck.length > 0) console.warn('Stuck chars:', stability.stuck);

    expect(stability.errors.length,
      `Sim threw ${stability.errors.length} error(s): ` +
      stability.errors.map(e => e.msg).join('; ')
    ).toBe(0);

