      `${stability.stuck.length} character(s) never left their spawn tile in 120s of sim-time: ` +
      stability.stuck.map(s => `${s.id}@(${s.spawn.tx},${s.spawn.ty})`).join(', ')
    ).toBe(0);
  });
});

