'use strict';
/**
 * REGRESSION — FRG-245
 * Character-to-character collision avoidance.
 *
 * Tests run against the local dev server (http://localhost:5175) which serves
 * the feature/frg-245-character-collision branch.
 *
 * The page does NOT expose window._gameEngine by default, so we intercept
 * index.html via page.route() and inject the exposure before the script executes.
 *
 * Test layout:
 *   1. No tile sharing — no two characters occupy the same tile when idle/interacting
 *   2. _moveCharWithCollision respects occupied tiles and preserves goal exemption
 *   3. Retry and deadlock escape — _retryTimer counts down, _deadlockEscape fires at 3 failures
 *   4. _findFreeInteractTile prefers unoccupied tiles when alternatives exist
 *   5. Live sim stability — no permanently stuck characters over 120s of sim time
 */
const { test, expect } = require('@playwright/test');

const LOCAL_URL = 'http://localhost:5175';
const MAP_COLS = 16; // from tilemap.js — width of tile grid

// ── helpers ──────────────────────────────────────────────────────────────────

/**
 * Intercept index.html and inject window._gameEngine = engine so tests can
 * call page.evaluate(() => window._gameEngine.*).
 */
async function injectEngineExposure(page) {
  await page.route('**/', async (route) => {
    const response = await route.fetch();
    let body = await response.text();
    body = body.replace(
      '// ── Initial state ──',
      '// ── Initial state (QA injection) ──\nwindow._gameEngine = engine;'
    );
    await route.fulfill({ response, body });
  });
}

/**
 * Click start overlay (if visible) and optionally boost timeScale.
 */
async function startEngine(page, timeScale = 1) {
  const overlay = page.locator('#start-overlay');
  if (await overlay.isVisible()) {
    await overlay.click();
  }
  if (timeScale !== 1) {
    await page.evaluate((scale) => {
      if (window._gameEngine) window._gameEngine.timeScale = scale;
    }, timeScale);
  }
}

/**
 * Poll engine snapshot until predicate returns truthy or timeout.
 */
async function pollSnapshot(page, predicate, timeoutMs = 45_000, intervalMs = 300) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const snap = await page.evaluate(() => window._gameEngine.snapshot());
    if (predicate(snap)) return snap;
    await page.waitForTimeout(intervalMs);
  }
  throw new Error(`pollSnapshot timed out after ${timeoutMs}ms`);
}

// ── Tests ─────────────────────────────────────────────────────────────────────

test.describe('FRG-245: Character Collision Avoidance', () => {

  // ── TEST 1: No tile sharing during idle/interacting ────────────────────────

  test('no two characters share a tile when idle or interacting over 60s', async ({ page }) => {
    test.setTimeout(120_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });
    await startEngine(page, 20); // 20x speed so 60 sim-seconds = ~3 real seconds

    const violations = [];
    const POLL_COUNT = 30;
    const POLL_INTERVAL_MS = 300; // ~9 real seconds at 20x = 180 sim-seconds

    for (let i = 0; i < POLL_COUNT; i++) {
      await page.waitForTimeout(POLL_INTERVAL_MS);

      const charPositions = await page.evaluate(() =>
        window._gameEngine.characters.map(c => ({
          id: c.id,
          tx: Math.round(c.tx),
          ty: Math.round(c.ty),
          action: c.action,
        }))
      );

      // Only check tile sharing when characters are in a stable state (idle/interacting)
      const stable = charPositions.filter(c => c.action === 'idle' || c.action === 'interacting');

      for (let a = 0; a < stable.length; a++) {
        for (let b = a + 1; b < stable.length; b++) {
          if (stable[a].tx === stable[b].tx && stable[a].ty === stable[b].ty) {
            violations.push({
              poll: i,
              charA: stable[a].id,
              charB: stable[b].id,
              tile: `(${stable[a].tx},${stable[a].ty})`,
              actions: `${stable[a].action}/${stable[b].action}`,
            });
          }
        }
      }
    }

    if (violations.length > 0) {
      console.error('Tile-sharing violations:', JSON.stringify(violations, null, 2));
    }

    expect(violations.length,
      `Characters shared tiles on ${violations.length} poll(s): ` +
      violations.map(v => `${v.charA}+${v.charB}@${v.tile}`).join(', ')
    ).toBe(0);
  });

  // ── TEST 2: _moveCharWithCollision respects occupied tiles ────────────────

  test('_moveCharWithCollision avoids occupied tiles but still reaches goal', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate((MAP_COLS) => {
      const engine = window._gameEngine;
      const [maple, sol, nyx] = engine.characters;

      // Place maple as a blocker mid-path
      maple.tx = 7; maple.ty = 4;

      // Place nyx as the mover — wants to reach (10, 4) but maple is at (7, 4)
      nyx.tx = 4; nyx.ty = 4;
      nyx.prevTx = 4; nyx.prevTy = 4;
      nyx.action = 'idle';
      nyx.path = [];
      nyx.moveProgress = 0;

      const blockerKey = maple.ty * MAP_COLS + maple.tx;

      // Move with collision — should avoid maple's tile
      const success = engine._moveCharWithCollision(nyx, 10, 4);

      if (!success) {
        return { success: false, pathKeys: [], blockerKey, blockerOnPath: false };
      }

      const pathKeys = nyx.path.map(step => step.ty * MAP_COLS + step.tx);
      const blockerOnPath = pathKeys.includes(blockerKey);

      return {
        success,
        pathKeys,
        blockerKey,
        blockerOnPath,
        pathLength: nyx.path.length,
      };
    }, MAP_COLS);

    console.log('_moveCharWithCollision result:', JSON.stringify(result));

    expect(result.success, 'Should find a path even with blocker in the way').toBe(true);
    expect(result.blockerOnPath,
      `Path must not route through blocker tile (key ${result.blockerKey})`
    ).toBe(false);
    expect(result.pathLength, 'Path should not be empty').toBeGreaterThan(0);
  });

  test('_moveCharWithCollision allows pathing to a tile even if it is occupied (goal exemption)', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate((MAP_COLS) => {
      const engine = window._gameEngine;
      const [maple, sol, nyx] = engine.characters;

      // Place maple directly on the goal tile
      maple.tx = 10; maple.ty = 4;

      // Nyx wants to reach (10, 4) — the tile occupied by maple
      nyx.tx = 4; nyx.ty = 4;
      nyx.prevTx = 4; nyx.prevTy = 4;
      nyx.action = 'idle';
      nyx.path = [];
      nyx.moveProgress = 0;

      // _moveCharWithCollision should still allow goal tile even if occupied
      const success = engine._moveCharWithCollision(nyx, 10, 4);

      return {
        success,
        goalIsOccupied: true, // we know it is: maple.tx=10, maple.ty=4
        pathLength: nyx.path.length,
      };
    }, MAP_COLS);

    console.log('Goal-exemption result:', JSON.stringify(result));

    expect(result.success,
      'Should be able to path to an occupied goal tile (goal exemption must hold)'
    ).toBe(true);
  });

  // ── TEST 3: Retry and deadlock escape ──────────────────────────────────────

  test('_retryTimer counts down and _retryCount increments on repeated failures', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const [maple, sol, nyx] = engine.characters;

      // Build a fake blocked-path scenario:
      // Nyx is idle with a _pendingTarget; _moveCharWithCollision will fail because
      // we pack all other characters onto the only viable path tile.

      // Place nyx in a corner-ish spot
      nyx.tx = 1; nyx.ty = 12;
      nyx.prevTx = 1; nyx.prevTy = 12;
      nyx.action = 'idle';
      nyx.path = [];
      nyx.moveProgress = 0;

      // Block the path to tile (2, 11) by placing sol and maple on adjacent tiles
      sol.tx = 2; sol.ty = 12;
      maple.tx = 1; maple.ty = 11;

      const fakeObj = engine.objectEngine.get('cafe_espresso');
      // Set up a _pendingTarget pointing to a blocked tile
      nyx._pendingTarget = { obj: fakeObj, action: 'use', tile: { tx: 3, ty: 11 } };
      nyx._retryCount = 1;
      nyx._retryTimer = 800; // 800ms remaining

      const before = {
        retryCount: nyx._retryCount,
        retryTimer: nyx._retryTimer,
        hasPendingTarget: !!nyx._pendingTarget,
      };

      // Advance 400ms — timer should partially count down but not fire yet
      engine._updateCharacters(400);

      const midpoint = {
        retryCount: nyx._retryCount,
        retryTimer: nyx._retryTimer,
        hasPendingTarget: !!nyx._pendingTarget,
      };

      return { before, midpoint };
    });

    console.log('Retry timer test:', JSON.stringify(result));

    expect(result.before.retryTimer, 'Timer should start at 800ms').toBe(800);
    expect(result.midpoint.retryTimer,
      'After 400ms, timer should have decreased by 400ms'
    ).toBeLessThan(800);
    expect(result.midpoint.retryTimer,
      'Timer should still be > 0 (400ms of 800ms elapsed)'
    ).toBeGreaterThan(0);
    expect(result.midpoint.hasPendingTarget,
      '_pendingTarget should still be set (timer has not fired yet)'
    ).toBe(true);
  });

  test('_deadlockEscape fires after 3 failed retries and moves char to adjacent free tile', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    const result = await page.evaluate(() => {
      const engine = window._gameEngine;
      const [maple, sol, nyx] = engine.characters;

      // Place nyx in the café sector with an open adjacency for escape
      nyx.tx = 8; nyx.ty = 14;
      nyx.prevTx = 8; nyx.prevTy = 14;
      nyx.action = 'idle';
      nyx.path = [];
      nyx.moveProgress = 0;

      // Block all neighbours EXCEPT one, to force a specific escape direction.
      // Adjacent tiles to (8,14): (8,13),(8,15),(7,14),(9,14)
      // Leave (9,14) free, block the rest with sol and maple
      sol.tx = 8; sol.ty = 13;
      maple.tx = 7; maple.ty = 14;
      // (8,15) is the floor below — check if it's walkable (it may be a wall)
      // For this test it doesn't matter — escape picks any free walkable tile.

      const fakeObj = engine.objectEngine.get('cafe_espresso');
      // Set retryCount = 3 so next expiry triggers _deadlockEscape
      nyx._pendingTarget = { obj: fakeObj, action: 'use', tile: { tx: 5, ty: 11 } };
      nyx._retryCount = 3;
      nyx._retryTimer = 10; // almost expired

      const before = { tx: nyx.tx, ty: nyx.ty, retryCount: nyx._retryCount };

      // Advance enough to fire the timer (10ms) and trigger escape
      engine._updateCharacters(50);

      const after = {
        tx: Math.round(nyx.tx),
        ty: Math.round(nyx.ty),
        action: nyx.action,
        retryCount: nyx._retryCount,
      };

      const moved = after.tx !== before.tx || after.ty !== before.ty;

      return { before, after, moved };
    });

    console.log('Deadlock escape test:', JSON.stringify(result));

    // After deadlock escape, character should have moved OR _pendingTarget was cleared (surrounded)
    // Either outcome is valid: escape moved char, or gave up cleanly.
    const escapedOrCleared = result.moved || result.after.retryCount === 0;
    expect(escapedOrCleared,
      'After 3 retries: character should escape to adjacent tile OR _retryCount reset to 0'
    ).toBe(true);

    if (result.moved) {
      const dist = Math.abs(result.after.tx - result.before.tx) + Math.abs(result.after.ty - result.before.ty);
      expect(dist, 'Escape should move exactly 1 tile (Manhattan distance)').toBeLessThanOrEqual(1);
    }
  });

  // ── TEST 4: _findFreeInteractTile prefers unoccupied tiles ────────────────

  test('_findFreeInteractTile returns an unoccupied tile when alternatives exist', async ({ page }) => {
    test.setTimeout(30_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });

    // Run multiple trials — the function is random, so we sample several times
    const TRIALS = 20;
    const result = await page.evaluate((TRIALS) => {
      const engine = window._gameEngine;
      const [maple, sol, nyx] = engine.characters;

      // Use cafe_espresso at (tx=2, ty=11) — single tile
      const espresso = engine.objectEngine.get('cafe_espresso');
      if (!espresso) return { error: 'cafe_espresso not found' };

      // Occupy ONE interact tile around espresso with maple.
      // Adjacent walkable tiles around (2,11): typically (1,11),(3,11),(2,10),(2,12)
      // We'll park maple at (1,11) — one of the interact tiles.
      maple.tx = 1; maple.ty = 11;

      // Nyx asks for a free interact tile — maple's tile should not be returned
      // (because at least one other candidate tile exists)
      const mapleKey = maple.ty * 16 + maple.tx; // MAP_COLS=16
      const trials = [];

      for (let i = 0; i < TRIALS; i++) {
        const tile = engine._findFreeInteractTile(espresso.position, nyx);
        if (!tile) {
          trials.push({ error: 'null' });
          continue;
        }
        const key = tile.ty * 16 + tile.tx;
        trials.push({ tx: tile.tx, ty: tile.ty, isMaple: key === mapleKey });
      }

      return { trials, maplePos: { tx: maple.tx, ty: maple.ty }, objPos: espresso.position };
    }, TRIALS);

    if (result.error) {
      console.log('[SKIP]', result.error);
      return;
    }

    console.log('_findFreeInteractTile trials:', JSON.stringify(result.trials));

    const nullCount = result.trials.filter(t => t.error === 'null').length;
    const mapleCount = result.trials.filter(t => t.isMaple).length;

    expect(nullCount,
      `_findFreeInteractTile should not return null when adjacents exist (got ${nullCount}/${TRIALS} nulls)`
    ).toBe(0);

    expect(mapleCount,
      `_findFreeInteractTile should never return maple's occupied tile when free alternatives exist ` +
      `(returned maple's tile ${mapleCount}/${TRIALS} times)`
    ).toBe(0);
  });

  // ── TEST 5: Live sim stability over 120s ──────────────────────────────────

  test('no character gets permanently stuck and sim stays stable over 120s', async ({ page }) => {
    test.setTimeout(180_000);

    await injectEngineExposure(page);
    await page.goto(LOCAL_URL);
    await page.waitForFunction(() => window._gameEngine?.characters?.length === 3, { timeout: 15_000 });
    await startEngine(page, 20); // 20x speed → 120 sim-seconds ≈ 6 real seconds

    // Drive 120 sim-seconds by advancing engine directly in a fast loop.
    // We take periodic snapshots to detect stuck characters (same tile, idle, no movement).
    const stability = await page.evaluate(() => {
      const engine = window._gameEngine;
      const STEP_MS = 500;          // 0.5 sim-second steps
      const TOTAL_SIM_MS = 120_000; // 120 sim-seconds
      const STEPS = TOTAL_SIM_MS / STEP_MS;

      const lastIdleSince = {};    // charId → sim-ms when they became idle at current tile
      const lastPos = {};          // charId → { tx, ty }
      const stuckEvents = [];      // characters idle > 30s at same tile
      let simMs = 0;

      for (const c of engine.characters) {
        lastPos[c.id] = { tx: Math.round(c.tx), ty: Math.round(c.ty) };
        lastIdleSince[c.id] = 0;
      }

      let errors = [];
      for (let step = 0; step < STEPS; step++) {
        try {
          engine._updateCharacters(STEP_MS);
        } catch (e) {
          errors.push({ step, simMs, msg: String(e) });
          break;
        }
        simMs += STEP_MS;

        for (const c of engine.characters) {
          const tx = Math.round(c.tx);
          const ty = Math.round(c.ty);

          if (c.action !== 'idle') {
            // Moving or interacting — not stuck
            lastPos[c.id] = { tx, ty };
            lastIdleSince[c.id] = simMs;
            continue;
          }

          // Idle: check if position changed
          if (tx !== lastPos[c.id].tx || ty !== lastPos[c.id].ty) {
            lastPos[c.id] = { tx, ty };
            lastIdleSince[c.id] = simMs;
          }

          const idleDuration = simMs - lastIdleSince[c.id];
          if (idleDuration > 30_000) {
            stuckEvents.push({ id: c.id, tx, ty, idleDuration, simMs });
            // Reset so we don't spam the same stuck event
            lastIdleSince[c.id] = simMs;
          }
        }
      }

      return { errors, stuckEvents, simMs };
    });

    console.log(`Sim ran for ${stability.simMs}ms sim-time`);
    if (stability.errors.length > 0) console.error('Sim errors:', stability.errors);
    if (stability.stuckEvents.length > 0) console.warn('Stuck events:', stability.stuckEvents);

    expect(stability.errors.length,
      `Sim threw ${stability.errors.length} error(s): ` +
      stability.errors.map(e => e.msg).join('; ')
    ).toBe(0);

    expect(stability.stuckEvents.length,
      `${stability.stuckEvents.length} character(s) were stuck for >30s: ` +
      stability.stuckEvents.map(e => `${e.id}@(${e.tx},${e.ty}) for ${e.idleDuration}ms`).join(', ')
    ).toBe(0);
  });
});
